import type { TimeFilters } from '../types'
import type { EPWData } from './schemas'
import type { WeatherDataPoint } from './weather-data'

interface TimeRange {
  start: number
  end: number
}

/**
 * Type guard to distinguish EPWData from WeatherDataPoint[].
 *
 * EPWData is an object with arrays (e.g., `{ month: number[], day: number[], ... }`).
 * WeatherDataPoint[] is an array of objects (e.g., `[{ dryBulbTemperature: 20 }, ...]`).
 *
 * @param data - The data to check.
 * @returns `true` if `data` is an EPWData object with the expected array fields.
 *
 * @example
 * ```ts
 * isEPWData({ month: [1, 2], day: [1, 2], hour: [0, 1], dryBulbTemperature: [20, 21] }) // true
 * isEPWData([{ dryBulbTemperature: 20 }]) // false
 * ```
 */
export function isEPWData(data: unknown): data is EPWData {
  if (!data || typeof data !== 'object') return false
  if (Array.isArray(data)) return false
  const obj = data as Record<string, unknown>
  return (
    Array.isArray(obj.month) &&
    Array.isArray(obj.day) &&
    Array.isArray(obj.hour) &&
    Array.isArray(obj.dryBulbTemperature)
  )
}

/**
 * Parse a range string like "6-15" into { start: 6, end: 15 }.
 * Also supports single values like "12" -> { start: 12, end: 12 }.
 */
function parseRange(rangeStr: string | undefined): TimeRange | null {
  if (!rangeStr) return null
  const parts = rangeStr.split('-').map(Number)
  if (parts.length === 1 && !Number.isNaN(parts[0])) {
    return { start: parts[0], end: parts[0] }
  }
  if (parts.length !== 2 || parts.some(Number.isNaN)) return null
  return { start: parts[0], end: parts[1] }
}

/**
 * Check if month falls within period (supports wrap-around like Nov-Feb)
 * Matches the backend Python logic:
 *   if start_month <= end_month:
 *     return start_month <= month <= end_month
 *   else:
 *     return month >= start_month or month <= end_month
 */
function isMonthInPeriod(month: number, startMonth: number, endMonth: number): boolean {
  if (startMonth <= endMonth) {
    // Normal case: Jan to Mar (1 to 3)
    return month >= startMonth && month <= endMonth
  } else {
    // Wrap-around case: Nov to Feb (11 to 2)
    return month >= startMonth || month <= endMonth
  }
}

/**
 * Filter EPW data by timeframe and optional day/hour ranges
 *
 * NOTE: Day filtering is currently DISABLED because the backend doesn't support
 * day filtering for sun_vector calculation yet. The logic is preserved (commented)
 * for future use when backend adds support.
 *
 * @param epw - Full EPW data structure with arrays
 * @param filters - Time filters with period and optional day/hour ranges
 * @returns Array of WeatherDataPoint matching the filter criteria
 */
export function filterEPWData(epw: EPWData, filters: TimeFilters): WeatherDataPoint[] {
  const { period, filter } = filters
  const startMonth = period.start.month
  const endMonth = period.end.month

  // Day filtering - DISABLED for now (backend doesn't support it yet)
  // Keep the logic for future use when backend adds day filtering support
  // const dayRange = parseRange(filter?.day)
  const hourRange = parseRange(filter?.hour)

  const result: WeatherDataPoint[] = []

  for (let i = 0; i < epw.month.length; i++) {
    const month = epw.month[i]
    // const day = epw.day[i]  // Disabled - backend doesn't use day filtering
    const hour = epw.hour[i]

    // Check month within period (supports wrap-around)
    if (!isMonthInPeriod(month, startMonth, endMonth)) {
      continue
    }

    // Day filtering - DISABLED
    // Backend calculates sun_vectors for all days in the month, so weather data
    // must include all days to match. Day filtering will be re-enabled when
    // backend supports it.
    // if (dayRange && (day < dayRange.start || day > dayRange.end)) {
    //   continue
    // }

    // Apply hour filter if specified
    if (hourRange && (hour < hourRange.start || hour > hourRange.end)) {
      continue
    }

    // Build WeatherDataPoint from arrays at index i
    result.push({
      dryBulbTemperature: epw.dryBulbTemperature[i] ?? null,
      dewPointTemperature: epw.dewPointTemperature[i] ?? null,
      relativeHumidity: epw.relativeHumidity[i] ?? null,
      atmosphericStationPressure: epw.atmosphericStationPressure[i] ?? null,
      extraterrestrialHorizontalRadiation: epw.extraterrestrialHorizontalRadiation[i] ?? null,
      extraterrestrialDirectNormalRadiation: epw.extraterrestrialDirectNormalRadiation[i] ?? null,
      horizontalInfraredRadiationIntensity: epw.horizontalInfraredRadiationIntensity[i] ?? null,
      globalHorizontalRadiation: epw.globalHorizontalRadiation[i] ?? null,
      directNormalRadiation: epw.directNormalRadiation[i] ?? null,
      diffuseHorizontalRadiation: epw.diffuseHorizontalRadiation[i] ?? null,
      globalHorizontalIlluminance: epw.globalHorizontalIlluminance[i] ?? null,
      directNormalIlluminance: epw.directNormalIlluminance[i] ?? null,
      diffuseHorizontalIlluminance: epw.diffuseHorizontalIlluminance[i] ?? null,
      zenithLuminance: epw.zenithLuminance[i] ?? null,
      windDirection: epw.windDirection[i] ?? null,
      windSpeed: epw.windSpeed[i] ?? null,
      totalSkyCover: epw.totalSkyCover[i] ?? null,
      opaqueSkyCover: epw.opaqueSkyCover[i] ?? null,
      visibility: epw.visibility[i] ?? null,
      ceilingHeight: epw.ceilingHeight[i] ?? null,
      presentWeatherObservation: epw.presentWeatherObservation[i] ?? null,
      presentWeatherCodes: epw.presentWeatherCodes[i] ?? null,
      precipitableWater: epw.precipitableWater[i] ?? null,
      aerosolOpticalDepth: epw.aerosolOpticalDepth[i] ?? null,
      snowDepth: epw.snowDepth[i] ?? null,
      daysSinceLastSnowfall: epw.daysSinceLastSnowfall[i] ?? null,
      albedo: epw.albedo[i] ?? null,
      liquidPrecipitationDepth: epw.liquidPrecipitationDepth[i] ?? null,
      liquidPrecipitationQuantity: epw.liquidPrecipitationQuantity[i] ?? null,
    })
  }

  return result
}
